#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {1, 2, 3};

    try
    {
        cout << numbers.at(5); // out of bounds
    }
    catch (out_of_range &e)
    {
        cout << "Caught: " << e.what() << endl;
    }

    return 0;
}

vector<int> numbers = {1, 2, 4};

numbers.insert(numbers.begin() + 2, 3); // insert 3 before index 2 → {1, 2, 3, 4}
numbers.erase(numbers.begin());          // remove the first element → {2, 3, 4}

